import{_ as t,o as a,c as i,a2 as s}from"./chunks/framework.CuteRReP.js";const u=JSON.parse('{"title":"Code Review — Request + Receive + Complete","description":"Full review lifecycle — request reviews, handle feedback with technical rigor, and complete branch integration. Use when completing tasks, receiving feedback, or finishing feature branches.","frontmatter":{"name":"cm-code-review","description":"Full review lifecycle — request reviews, handle feedback with technical rigor, and complete branch integration. Use when completing tasks, receiving feedback, or finishing feature branches."},"headers":[],"relativePath":"skills/cm-code-review.md","filePath":"skills/cm-code-review.md"}'),n={name:"skills/cm-code-review.md"};function r(o,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="code-review-—-request-receive-complete" tabindex="-1">Code Review — Request + Receive + Complete <a class="header-anchor" href="#code-review-—-request-receive-complete" aria-label="Permalink to &quot;Code Review — Request + Receive + Complete&quot;">​</a></h1><blockquote><p><strong>Full review lifecycle in one skill:</strong> Request → Receive → Integrate.</p></blockquote><h2 id="part-a-requesting-code-review" tabindex="-1">Part A: Requesting Code Review <a class="header-anchor" href="#part-a-requesting-code-review" aria-label="Permalink to &quot;Part A: Requesting Code Review&quot;">​</a></h2><h3 id="when-to-request" tabindex="-1">When to Request <a class="header-anchor" href="#when-to-request" aria-label="Permalink to &quot;When to Request&quot;">​</a></h3><p><strong>Mandatory:</strong></p><ul><li>After each task in <code>cm-execution</code></li><li>After completing major features</li><li>Before merge to main</li></ul><p><strong>Optional but valuable:</strong></p><ul><li>When stuck (fresh perspective)</li><li>Before refactoring (baseline check)</li><li>After fixing complex bugs</li></ul><h3 id="how-to-request" tabindex="-1">How to Request <a class="header-anchor" href="#how-to-request" aria-label="Permalink to &quot;How to Request&quot;">​</a></h3><ol><li><p><strong>Get git SHAs:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BASE_SHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HEAD_SHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p><strong>Dispatch reviewer subagent</strong> with:</p><ul><li>What was implemented</li><li>Plan/requirements reference</li><li>Base and head SHAs</li><li>Brief description</li></ul></li><li><p><strong>Act on feedback:</strong></p><ul><li>Fix Critical issues immediately</li><li>Fix Important issues before proceeding</li><li>Note Minor issues for later</li><li>Push back if reviewer is wrong (with reasoning)</li></ul></li></ol><hr><h2 id="part-b-receiving-code-review" tabindex="-1">Part B: Receiving Code Review <a class="header-anchor" href="#part-b-receiving-code-review" aria-label="Permalink to &quot;Part B: Receiving Code Review&quot;">​</a></h2><h3 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h3><p>When receiving feedback — whether from human reviewers, AI reviewers, or code review subagents.</p><h3 id="the-protocol" tabindex="-1">The Protocol <a class="header-anchor" href="#the-protocol" aria-label="Permalink to &quot;The Protocol&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. READ feedback completely before responding</span></span>
<span class="line"><span>2. UNDERSTAND the technical reasoning</span></span>
<span class="line"><span>3. VERIFY if the feedback is technically correct</span></span>
<span class="line"><span>4. RESPOND with evidence, not agreement</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="response-framework" tabindex="-1">Response Framework <a class="header-anchor" href="#response-framework" aria-label="Permalink to &quot;Response Framework&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feedback Type</th><th>Response</th></tr></thead><tbody><tr><td><strong>Technically correct</strong></td><td>Fix it. Thank reviewer.</td></tr><tr><td><strong>Unclear intent</strong></td><td>Ask for clarification with specific questions</td></tr><tr><td><strong>Technically questionable</strong></td><td>Challenge with evidence (code, tests, docs)</td></tr><tr><td><strong>Stylistic preference</strong></td><td>Discuss trade-offs, defer to team convention</td></tr></tbody></table><h3 id="red-flags-—-stop" tabindex="-1">Red Flags — STOP <a class="header-anchor" href="#red-flags-—-stop" aria-label="Permalink to &quot;Red Flags — STOP&quot;">​</a></h3><ul><li>Blindly implementing all suggestions without verification</li><li>&quot;Performative agreement&quot; — saying yes without understanding</li><li>Implementing a suggestion that breaks existing tests</li><li>Making changes you can&#39;t justify technically</li></ul><h3 id="anti-pattern-performative-agreement" tabindex="-1">Anti-Pattern: Performative Agreement <a class="header-anchor" href="#anti-pattern-performative-agreement" aria-label="Permalink to &quot;Anti-Pattern: Performative Agreement&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ &quot;Good catch! Fixed.&quot;  (without verifying it&#39;s actually a problem)</span></span>
<span class="line"><span>✅ &quot;I verified this: [evidence]. The suggestion is correct because [reason]. Fixed.&quot;</span></span>
<span class="line"><span>✅ &quot;I investigated this: [evidence]. The current code is correct because [reason].&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="part-c-finishing-a-development-branch" tabindex="-1">Part C: Finishing a Development Branch <a class="header-anchor" href="#part-c-finishing-a-development-branch" aria-label="Permalink to &quot;Part C: Finishing a Development Branch&quot;">​</a></h2><h3 id="when-to-use-1" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use-1" aria-label="Permalink to &quot;When to Use&quot;">​</a></h3><p>When implementation is complete and all tests pass.</p><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li><p><strong>Verify current state:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:gate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # All tests must pass</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Working tree should be clean</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p><strong>Present options to user:</strong></p><table tabindex="0"><thead><tr><th>Option</th><th>When</th><th>Command</th></tr></thead><tbody><tr><td><strong>Merge to main</strong></td><td>Feature ready</td><td><code>git checkout main &amp;&amp; git merge feature-branch</code></td></tr><tr><td><strong>Create PR</strong></td><td>Needs team review</td><td><code>git push origin feature-branch</code></td></tr><tr><td><strong>Keep working</strong></td><td>More tasks remain</td><td>Continue on branch</td></tr><tr><td><strong>Cleanup only</strong></td><td>Abandoned/merged</td><td><code>git worktree remove path</code></td></tr></tbody></table></li><li><p><strong>Execute chosen option</strong></p></li><li><p><strong>Cleanup:</strong></p><ul><li>Remove worktree if using <code>cm-git-worktrees</code></li><li>Delete feature branch if merged</li><li>Update task tracking</li></ul></li></ol><h3 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>Never merge with failing tests</li><li>Never force push main/production</li><li>Always use <code>cm-identity-guard</code> before git push</li></ul><hr><h2 id="part-d-security-review-checklist-learned-march-2026" tabindex="-1">Part D: Security Review Checklist (Learned: March 2026) <a class="header-anchor" href="#part-d-security-review-checklist-learned-march-2026" aria-label="Permalink to &quot;Part D: Security Review Checklist (Learned: March 2026)&quot;">​</a></h2><blockquote><p><strong>Every code review MUST include a security pass.</strong> Check these patterns:</p></blockquote><h3 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h3><ul><li>[ ] No <code>innerHTML</code> with unescaped dynamic data</li><li>[ ] <code>sanitize.js</code> loaded before any JS that uses <code>innerHTML</code></li><li>[ ] URLs from params validated against allowlist</li><li>[ ] No <code>eval()</code>, <code>new Function()</code>, or <code>document.write()</code> with user data</li></ul><h3 id="backend-python" tabindex="-1">Backend (Python) <a class="header-anchor" href="#backend-python" aria-label="Permalink to &quot;Backend (Python)&quot;">​</a></h3><ul><li>[ ] All file paths from config/input use <code>safe_resolve(base, path)</code></li><li>[ ] No <code>subprocess.run(..., shell=True)</code> with dynamic args</li><li>[ ] No <code>open(user_input)</code> without path validation</li></ul><h3 id="backend-node-express" tabindex="-1">Backend (Node/Express) <a class="header-anchor" href="#backend-node-express" aria-label="Permalink to &quot;Backend (Node/Express)&quot;">​</a></h3><ul><li>[ ] <code>app.disable(&#39;x-powered-by&#39;)</code> set</li><li>[ ] Body size limits configured</li><li>[ ] No <code>Object.assign(config, userInput)</code> (prototype pollution)</li><li>[ ] API error responses don&#39;t leak stack traces</li></ul><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><ul><li>[ ] No secrets/API keys in committed code</li><li>[ ] <code>.snyk</code> exclusions documented with mitigation rationale</li></ul><hr><h3 id="step-final-record-review-learnings" tabindex="-1">Step FINAL: Record Review Learnings <a class="header-anchor" href="#step-final-record-review-learnings" aria-label="Permalink to &quot;Step FINAL: Record Review Learnings&quot;">​</a></h3><p>After processing review feedback, ALWAYS update <code>.cm/CONTINUITY.md</code>:</p><ul><li><strong>Key Decisions:</strong> If reviewer changed architecture approach, record with scope: <code>[Decision]: [Rationale] — scope: [global|module:{name}]</code></li><li><strong>Mistakes &amp; Learnings:</strong> If reviewer caught a pattern mistake, record with scope: <ul><li>What Failed: [the pattern that was wrong]</li><li>How to Prevent: [correct pattern going forward]</li><li>Scope: [global | module:{name} | file:{path}]</li></ul></li></ul><p><strong>Anti-duplicate:</strong> If similar learning exists, reinforce it instead of creating new.</p><blockquote><p><strong>Token savings:</strong> Future code reviews in same project avoid repeating the same feedback. Reviewer patterns become accumulated knowledge.</p></blockquote><hr><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Relationship</th></tr></thead><tbody><tr><td><code>cm-execution</code></td><td>Reviews after each task in execution</td></tr><tr><td><code>cm-quality-gate</code></td><td>Tests must pass before finishing branch</td></tr><tr><td><code>cm-identity-guard</code></td><td>Before git push</td></tr><tr><td><code>cm-git-worktrees</code></td><td>Cleanup worktree after completion</td></tr></tbody></table><h2 id="the-bottom-line" tabindex="-1">The Bottom Line <a class="header-anchor" href="#the-bottom-line" aria-label="Permalink to &quot;The Bottom Line&quot;">​</a></h2><p><strong>Review early. Verify feedback. Ship with evidence, not hope.</strong></p>`,52)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
